# @cctt_verify {"v":2,"sym":"sympy.printing.tests.test_julia.test_julia_piecewise","kind":"function","src_hash":"5f655f8ab9bea598","in":{"base":"Any"},"out":{"base":"Any","pred":"julia_code(expr) == '((x < 1) ? (x) : (x .^ 2))' and julia_code(expr, assign_to='r') == 'r = ((x < 1) ? (x) : (x .^ 2))' and julia_code(expr) == expected and julia_code(expr, assign_to='r') == 'r = ' + expected"},"spec":{"lhs":"test_julia_piecewise()","rhs":"test_julia_piecewise produces the expected output","over":{"base":"Any"},"name":"test_julia_piecewise_correct"},"guarantee":"test_julia_piecewise produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.printing.tests.test_julia.test_julia_piecewise_correct","statement":"Path(test_julia_piecewise(x), test_julia_piecewise produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"49b82400f6b8d896"}
def test_julia_piecewise():
    expr = Piecewise((x, x < 1), (x**2, True))
    assert julia_code(expr) == "((x < 1) ? (x) : (x .^ 2))"
    assert julia_code(expr, assign_to="r") == (
        "r = ((x < 1) ? (x) : (x .^ 2))")
    assert julia_code(expr, assign_to="r", inline=False) == (
        "if (x < 1)\n"
        "    r = x\n"
        "else\n"
        "    r = x .^ 2\n"
        "end")
    expr = Piecewise((x**2, x < 1), (x**3, x < 2), (x**4, x < 3), (x**5, True))
    expected = ("((x < 1) ? (x .^ 2) :\n"
                "(x < 2) ? (x .^ 3) :\n"
                "(x < 3) ? (x .^ 4) : (x .^ 5))")
    assert julia_code(expr) == expected
    assert julia_code(expr, assign_to="r") == "r = " + expected
    assert julia_code(expr, assign_to="r", inline=False) == (
        "if (x < 1)\n"
        "    r = x .^ 2\n"
        "elseif (x < 2)\n"
        "    r = x .^ 3\n"
        "elseif (x < 3)\n"
        "    r = x .^ 4\n"
        "else\n"
        "    r = x .^ 5\n"
        "end")
    # Check that Piecewise without a True (default) condition error
    expr = Piecewise((x, x < 1), (x**2, x > 1), (sin(x), x > 0))
    raises(ValueError, lambda: julia_code(expr))


